#include <vector>
#include <string>
#include <set>

using namespace std;

vector<string> solve(string s) {
    vector<string> segments;
    set<string> seen;
    string current;

    for (int i = 0; i < s.length(); ++i) {
        current += s[i];
        if (seen.find(current) == seen.end()) {
            seen.insert(current);
        } else {
            // If current is already seen, we need to split
            // So we add the previous segment and start new
            segments.push_back(current);
            current = "";
            seen.clear();
            seen.insert(current);
        }
    }

    // Add the last segment
    if (!current.empty()) {
        segments.push_back(current);
    }

    return segments;
}
